export interface Question {
  id: number;
  question: string;
  options: string[];
  correct: number;
  explanation: string;
  difficulty: "beginner" | "intermediate" | "advanced";
  topic: string;
  learnLink: string;
}

export const allQuestions: Question[] = [
  // ── STOCKS ──────────────────────────────────────────
  { id: 1, question: "What does owning a stock mean?", options: ["You lent money to a company", "You own a piece of a company", "You guaranteed a company's debt", "You work for the company"], correct: 1, explanation: "A stock represents partial ownership in a company. You become a shareholder!", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 6, question: "What is the P/E ratio?", options: ["Price to Earnings ratio", "Profit to Expense ratio", "Payment to Equity ratio", "Percentage of Earnings"], correct: 0, explanation: "The P/E ratio compares a stock's price to its earnings per share — it helps you evaluate if a stock is over or undervalued.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 12, question: "What does 'bull market' mean?", options: ["A market that's declining", "A market that's rising", "A market with no change", "A market for agriculture"], correct: 1, explanation: "A bull market means prices are rising or expected to rise. Think of a bull charging upward with its horns!", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 21, question: "What is market capitalization?", options: ["Total revenue of a company", "Share price multiplied by total shares outstanding", "The company's total debt", "Annual profit of a company"], correct: 1, explanation: "Market cap = share price × total shares. It tells you the market's valuation of a company's equity.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 22, question: "What is a bear market?", options: ["A market rising more than 20%", "A market falling more than 20%", "A flat market", "A market for commodities"], correct: 1, explanation: "A bear market is a 20%+ decline from recent highs. Historically, they last an average of about 9-12 months.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 26, question: "What is beta in investing?", options: ["A company's profit margin", "A measure of a stock's volatility relative to the market", "The dividend yield", "A type of bond rating"], correct: 1, explanation: "Beta measures how much a stock moves relative to the overall market. A beta > 1 means more volatile, < 1 means less volatile.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 31, question: "What does EPS (Earnings Per Share) measure?", options: ["Total company revenue", "Profit allocated to each outstanding share of stock", "The stock's trading volume", "Dividends paid per share"], correct: 1, explanation: "EPS = Net Income ÷ Outstanding Shares. It's one of the most important metrics for evaluating a company's profitability on a per-share basis.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 32, question: "What is a stock split and why do companies do it?", options: ["Selling half the company", "Dividing existing shares into more shares at a lower price", "Merging two companies' stocks", "Removing a stock from an exchange"], correct: 1, explanation: "A stock split increases the number of shares while proportionally reducing the price per share. It makes shares more accessible to smaller investors without changing the company's total value.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 33, question: "What is the difference between a market order and a limit order?", options: ["Market orders are for bonds, limit orders are for stocks", "Market orders execute immediately at current price; limit orders set a specific price", "Limit orders are faster than market orders", "There is no difference"], correct: 1, explanation: "A market order executes immediately at the best available price. A limit order only executes at your specified price or better, giving you more control but no guarantee of execution.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 34, question: "What does 'short selling' a stock mean?", options: ["Selling a stock quickly", "Borrowing shares to sell them, hoping to buy back at a lower price", "Selling shares you've owned for less than a year", "Buying a stock at a discount"], correct: 1, explanation: "Short selling involves borrowing shares from a broker, selling them at the current price, and hoping to buy them back later at a lower price to return to the lender, pocketing the difference.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 35, question: "What is a blue-chip stock?", options: ["A stock that costs less than $5", "A well-established, financially sound, large-cap company stock", "A stock in the technology sector", "A newly listed stock"], correct: 1, explanation: "Blue-chip stocks are shares of large, well-established companies with a history of reliable performance — think Apple, Johnson & Johnson, or Coca-Cola. The term comes from poker, where blue chips have the highest value.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 36, question: "What is the difference between growth stocks and value stocks?", options: ["Growth stocks pay dividends, value stocks don't", "Growth stocks are expected to grow faster; value stocks trade below intrinsic value", "Value stocks are more expensive", "There is no meaningful difference"], correct: 1, explanation: "Growth stocks are companies expected to grow earnings faster than average (often reinvesting profits). Value stocks appear undervalued based on fundamentals like P/E ratio. Both have delivered strong long-term returns.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 37, question: "What does market capitalization tell you about a company?", options: ["How much debt the company has", "The total market value of its outstanding shares", "Its annual revenue", "The number of employees"], correct: 1, explanation: "Market cap = share price × total shares outstanding. Large-cap (>$10B), mid-cap ($2-10B), and small-cap (<$2B) classifications help investors understand company size and risk profile.", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 38, question: "What is insider trading and why is it illegal?", options: ["Trading during after-hours markets", "Trading based on non-public material information for profit", "Trading stocks in foreign markets", "Buying stocks through a financial advisor"], correct: 1, explanation: "Insider trading involves using confidential, non-public information to make investment decisions. It's illegal because it gives an unfair advantage and undermines market integrity and public trust.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },

  // ── ETFs ──────────────────────────────────────────
  { id: 2, question: "What is an ETF?", options: ["A type of bank account", "A government bond", "A basket of investments traded like a stock", "An insurance product"], correct: 2, explanation: "ETFs bundle multiple investments together and trade on exchanges, giving you instant diversification.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 13, question: "What is the expense ratio of a fund?", options: ["The fund's total assets", "The annual fee charged as a percentage of assets", "The fund's rate of return", "The minimum investment amount"], correct: 1, explanation: "The expense ratio is the annual cost of owning a fund. Even small differences (0.1% vs 1%) compound into huge amounts over decades.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 24, question: "What is a mutual fund's load?", options: ["Its total assets", "A sales commission charged to investors", "Its annual return", "The number of stocks it holds"], correct: 1, explanation: "A 'load' is a sales commission. No-load funds don't charge this fee — always prefer no-load funds to keep more of your returns.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 30, question: "What is an expense ratio considered low?", options: ["Under 5%", "Under 1%", "Under 0.20%", "Under 10%"], correct: 2, explanation: "Index funds often have expense ratios under 0.10%. Anything above 0.50% is considered high for a passively managed fund.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 39, question: "What is the difference between an ETF and a mutual fund?", options: ["ETFs can only hold stocks", "ETFs trade throughout the day like stocks; mutual funds are priced once daily", "Mutual funds have lower fees", "ETFs are only for retirement accounts"], correct: 1, explanation: "ETFs trade on exchanges throughout the day at market-determined prices, while mutual funds are bought/sold at end-of-day NAV. ETFs also tend to be more tax-efficient due to their in-kind creation/redemption mechanism.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 40, question: "What does 'tracking error' mean for an index ETF?", options: ["The ETF's total return", "The difference between the ETF's performance and the index it tracks", "The price of the ETF", "The number of holdings in the ETF"], correct: 1, explanation: "Tracking error measures how closely an ETF follows its benchmark index. A lower tracking error means the ETF is doing a better job replicating the index's performance.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 41, question: "What is a sector ETF?", options: ["An ETF that holds only bonds", "An ETF focused on a specific industry like technology or healthcare", "An ETF for international markets only", "An ETF with high fees"], correct: 1, explanation: "Sector ETFs focus on specific industries (XLK for tech, XLV for healthcare, XLE for energy). They allow targeted exposure but are less diversified than broad-market ETFs.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 42, question: "What does 'assets under management' (AUM) mean?", options: ["The number of investors in a fund", "The total market value of investments managed by a fund", "The fund's expense ratio", "The fund manager's salary"], correct: 1, explanation: "AUM represents the total market value of all assets a fund manages on behalf of its investors. Higher AUM generally indicates greater investor confidence and can lead to lower expense ratios.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 43, question: "What is the bid-ask spread on an ETF?", options: ["The annual fee", "The difference between what buyers will pay and sellers will accept", "The ETF's dividend yield", "The fund's total return"], correct: 1, explanation: "The bid-ask spread is the difference between the highest price a buyer is willing to pay (bid) and the lowest price a seller will accept (ask). Tighter spreads mean lower trading costs for investors.", difficulty: "intermediate", topic: "etfs", learnLink: "etfs" },
  { id: 44, question: "What is an inverse ETF?", options: ["An ETF that tracks foreign markets", "An ETF designed to profit when its benchmark index declines", "An ETF with no expense ratio", "An ETF that only holds bonds"], correct: 1, explanation: "Inverse ETFs use derivatives to move in the opposite direction of their benchmark. If the S&P 500 drops 1%, an inverse S&P 500 ETF aims to gain 1%. They're risky and meant for short-term trading, not long-term holding.", difficulty: "advanced", topic: "etfs", learnLink: "etfs" },

  // ── BONDS ──────────────────────────────────────────
  { id: 5, question: "What is a bond?", options: ["Ownership in a company", "A loan you give to a government or corporation", "A type of stock", "A savings account"], correct: 1, explanation: "When you buy a bond, you're essentially lending money and earning interest in return.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 7, question: "What happens to bond prices when interest rates rise?", options: ["They go up", "They go down", "They stay the same", "They become worthless"], correct: 1, explanation: "Bond prices move inversely to interest rates. When rates rise, existing bonds become less attractive, so their prices fall.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 28, question: "What is a yield curve inversion?", options: ["When stocks outperform bonds", "When short-term rates exceed long-term rates", "When dividends increase", "When inflation drops"], correct: 1, explanation: "An inverted yield curve — short-term bonds paying more than long-term — has historically preceded recessions.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 45, question: "What is a bond's 'coupon rate'?", options: ["The discount for buying early", "The annual interest rate paid to bondholders", "The bond's maturity date", "The fee to sell a bond"], correct: 1, explanation: "The coupon rate is the annual interest payment expressed as a percentage of the bond's face value. A $1,000 bond with a 5% coupon pays $50 per year in interest.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 46, question: "What does it mean when a bond is 'callable'?", options: ["It can be traded on an exchange", "The issuer can redeem it before the maturity date", "It has no maturity date", "It pays variable interest"], correct: 1, explanation: "A callable bond gives the issuer the right to repay the principal before maturity, usually when interest rates drop. This is a disadvantage to investors because they lose the higher coupon payments.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 47, question: "What is the difference between investment grade and junk bonds?", options: ["Junk bonds have lower yields", "Investment grade bonds have higher credit ratings and lower default risk", "They are the same thing", "Investment grade bonds have higher yields"], correct: 1, explanation: "Investment grade bonds (rated BBB/Baa or higher) have lower default risk but lower yields. Junk bonds (below BBB) carry higher default risk but offer higher yields to compensate investors.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 48, question: "What is a Treasury Inflation-Protected Security (TIPS)?", options: ["A type of stock", "A government bond whose principal adjusts with inflation", "A high-yield savings account", "A corporate bond"], correct: 1, explanation: "TIPS are U.S. government bonds where the principal value adjusts based on the Consumer Price Index (CPI). They protect your purchasing power against inflation.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 49, question: "What is 'duration' in bond investing?", options: ["How long you've owned the bond", "A measure of a bond's price sensitivity to interest rate changes", "The time between coupon payments", "The bond's credit rating"], correct: 1, explanation: "Duration measures how much a bond's price will change when interest rates move. Higher duration = more sensitivity. A bond with 5-year duration loses ~5% in value if rates rise 1%.", difficulty: "advanced", topic: "bonds", learnLink: "bonds" },
  { id: 50, question: "What is a municipal bond and who benefits most from them?", options: ["A bond issued by a corporation; benefits employees", "A bond issued by state/local governments; benefits high-tax-bracket investors", "A federal government bond; benefits retirees", "A bond issued by banks; benefits borrowers"], correct: 1, explanation: "Municipal bonds are issued by state and local governments. Their interest is often exempt from federal income tax (and sometimes state/local tax), making them especially attractive to investors in high tax brackets.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },

  // ── RETIREMENT ──────────────────────────────────────
  { id: 11, question: "What's the difference between a Roth IRA and Traditional IRA?", options: ["Roth has no tax benefits", "Roth is taxed now, Traditional is taxed later", "Traditional is taxed now, Roth is taxed later", "They are the same"], correct: 1, explanation: "With a Roth IRA, you pay taxes now and withdraw tax-free in retirement. Traditional IRAs give you a tax break now but you pay taxes on withdrawals.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 25, question: "What is the 4% rule in retirement planning?", options: ["Save 4% of your income", "Withdraw 4% of your portfolio annually in retirement", "Earn at least 4% returns", "Invest in 4 different assets"], correct: 1, explanation: "The 4% rule suggests you can withdraw 4% per year from your retirement portfolio with a high probability of not running out of money over 30 years.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 51, question: "What is a Required Minimum Distribution (RMD)?", options: ["The minimum you must contribute to a 401k", "The mandatory minimum amount you must withdraw from tax-deferred retirement accounts starting at age 73", "The minimum balance required in an IRA", "The smallest trade allowed on an exchange"], correct: 1, explanation: "RMDs are mandatory withdrawals from Traditional IRAs and 401(k)s starting at age 73. The IRS requires them because it wants to eventually collect taxes on your tax-deferred savings.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 52, question: "At what age can you withdraw from a Traditional IRA penalty-free?", options: ["55", "59½", "62", "65"], correct: 1, explanation: "You can withdraw from a Traditional IRA without the 10% early withdrawal penalty at age 59½. You'll still owe ordinary income tax on the withdrawals.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 53, question: "What is a Roth conversion?", options: ["Closing a Roth IRA", "Moving money from a Traditional IRA to a Roth IRA and paying taxes on it", "Converting stocks to bonds", "Changing your 401k contribution amount"], correct: 1, explanation: "A Roth conversion involves transferring funds from a Traditional IRA to a Roth IRA. You pay income tax on the converted amount now, but future growth and withdrawals are tax-free.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 54, question: "What is a 403(b) plan?", options: ["A type of Roth IRA", "A retirement plan for public school and nonprofit employees, similar to a 401k", "A health savings account", "A college savings plan"], correct: 1, explanation: "A 403(b) is the nonprofit/public sector equivalent of a 401(k). It offers similar tax advantages and contribution limits, though the investment options may be more limited.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 55, question: "What is the difference between a traditional 401k and a Roth 401k?", options: ["There is no difference", "Traditional contributions are pre-tax; Roth contributions are after-tax", "Roth 401k has no employer match", "Traditional 401k has lower contribution limits"], correct: 1, explanation: "Traditional 401(k) contributions reduce your taxable income now but are taxed on withdrawal. Roth 401(k) contributions are made after tax, but withdrawals in retirement are tax-free.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 56, question: "What is an HSA and what makes it uniquely tax-advantaged?", options: ["A type of 401k", "A health savings account with triple tax benefits: deductible contributions, tax-free growth, and tax-free medical withdrawals", "A type of pension plan", "A bank account for home purchases"], correct: 1, explanation: "HSAs offer a unique 'triple tax advantage': contributions are tax-deductible, growth is tax-free, and withdrawals for qualified medical expenses are tax-free. After age 65, you can withdraw for any reason (taxed like a Traditional IRA).", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 57, question: "What is vesting in a 401k context?", options: ["The process of choosing investments", "How much of your employer's contributions you get to keep based on tenure", "Setting up automatic contributions", "Withdrawing funds early"], correct: 1, explanation: "Vesting determines how much of your employer's matching contributions you own. A typical vesting schedule might give you 20% per year, so after 5 years you're '100% vested' and own all the matched funds.", difficulty: "beginner", topic: "retirement", learnLink: "retirement" },
  { id: 58, question: "What is the backdoor Roth IRA strategy?", options: ["A way to avoid paying taxes entirely", "Contributing to a Traditional IRA then converting to a Roth IRA to bypass income limits", "A secret retirement account", "Withdrawing from a Roth IRA early"], correct: 1, explanation: "The backdoor Roth IRA is a legal strategy for high earners who exceed Roth IRA income limits. You contribute to a non-deductible Traditional IRA, then immediately convert it to a Roth IRA.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },

  // ── TAXES ──────────────────────────────────────────
  { id: 8, question: "What is tax-loss harvesting?", options: ["Paying extra taxes on gains", "Selling losing investments to offset gains", "Avoiding all stock sales", "Only buying tax-free bonds"], correct: 1, explanation: "Tax-loss harvesting means strategically selling investments at a loss to offset capital gains taxes — a smart year-end strategy!", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 59, question: "What is the wash sale rule?", options: ["A rule about cleaning investment records", "A rule that disallows a tax deduction if you buy a substantially identical security within 30 days of selling at a loss", "A rule about selling stocks on the same day", "A rule about dividend reinvestment"], correct: 1, explanation: "The wash sale rule prevents you from claiming a tax loss if you repurchase the same or substantially identical security within 30 days before or after the sale. The disallowed loss gets added to the cost basis of the new shares.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 60, question: "What is the difference between short-term and long-term capital gains?", options: ["There is no tax difference", "Short-term (held <1 year) is taxed as ordinary income; long-term (held >1 year) gets a lower rate", "Long-term gains are taxed more heavily", "Short-term gains are tax-free"], correct: 1, explanation: "Investments held for more than one year qualify for lower long-term capital gains rates (0%, 15%, or 20% depending on income). Short-term gains are taxed at your ordinary income rate, which can be up to 37%.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },
  { id: 61, question: "What is tax-gain harvesting?", options: ["Selling winners to increase your tax bill", "Strategically realizing capital gains in years when you're in a low tax bracket", "A type of tax fraud", "Investing only in tax-free bonds"], correct: 1, explanation: "Tax-gain harvesting means selling appreciated investments when you're in the 0% long-term capital gains bracket (e.g., a gap year, early retirement) to reset the cost basis to a higher level — effectively locking in gains tax-free.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 62, question: "What is asset location strategy?", options: ["Choosing which country to invest in", "Placing investments in the most tax-efficient account types", "Buying local stocks only", "Diversifying across sectors"], correct: 1, explanation: "Asset location means holding tax-inefficient investments (bonds, REITs) in tax-advantaged accounts (IRA, 401k) and tax-efficient investments (index funds, growth stocks) in taxable accounts to minimize your overall tax burden.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },
  { id: 63, question: "What are qualified dividends?", options: ["Dividends from government bonds", "Dividends that meet IRS holding requirements and are taxed at lower capital gains rates", "Dividends paid monthly", "All dividends from U.S. companies"], correct: 1, explanation: "Qualified dividends are taxed at the lower long-term capital gains rate (0%, 15%, or 20%) rather than your ordinary income rate. To qualify, you must hold the stock for at least 61 days during the 121-day period around the ex-dividend date.", difficulty: "intermediate", topic: "taxes", learnLink: "taxes" },
  { id: 64, question: "What is a step-up in basis at death?", options: ["An increase in stock price after an IPO", "When inherited assets are revalued to their current market value, eliminating unrealized gains", "A type of estate tax", "An increase in 401k contributions"], correct: 1, explanation: "When you inherit an asset, its cost basis 'steps up' to its fair market value at the date of death. If your parent bought stock at $10 and it's worth $100 when they pass, your basis is $100 — all those unrealized gains are never taxed.", difficulty: "advanced", topic: "taxes", learnLink: "taxes" },

  // ── BEHAVIORAL FINANCE ──────────────────────────────
  { id: 14, question: "What is loss aversion?", options: ["Avoiding all investments", "Feeling losses more intensely than equivalent gains", "A trading strategy", "A type of insurance"], correct: 1, explanation: "Research shows we feel the pain of losing $100 about twice as intensely as the pleasure of gaining $100. This bias causes investors to make irrational decisions.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 65, question: "What is confirmation bias in investing?", options: ["Confirming your account balance regularly", "Seeking out information that supports your existing beliefs while ignoring contradictory evidence", "A strategy for verifying stock tips", "Reading multiple news sources"], correct: 1, explanation: "Confirmation bias leads investors to seek information that validates their position and dismiss evidence against it. This can keep you holding a losing investment because you only read positive news about the company.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 66, question: "What is the sunk cost fallacy?", options: ["Not investing enough money", "Continuing an action because of past investments rather than future value", "A way to calculate investment losses", "A tax deduction strategy"], correct: 1, explanation: "The sunk cost fallacy causes investors to hold losing positions because they've 'already invested so much.' The money already spent shouldn't influence future decisions — only the expected future value matters.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 67, question: "What is anchoring bias?", options: ["Always investing in the same stock", "Over-relying on the first piece of information you encounter when making decisions", "A method for setting stop-loss orders", "A portfolio balancing technique"], correct: 1, explanation: "Anchoring causes investors to fixate on a reference point (like the price they bought a stock at) and make decisions based on it, even when it's irrelevant. 'It was $100, now it's $50, so it must be cheap' ignores whether $50 is actually a fair value.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 68, question: "What is the disposition effect?", options: ["The tendency to diversify", "Selling winners too early and holding losers too long", "A method for disposing of bad investments", "A tax strategy"], correct: 1, explanation: "The disposition effect causes investors to sell winning investments too quickly (to 'lock in gains') while holding losers too long (hoping they'll recover). This is the opposite of the optimal strategy.", difficulty: "advanced", topic: "behavioral", learnLink: "behavioral" },
  { id: 69, question: "What is mental accounting?", options: ["Using a financial calculator", "Treating money differently based on its source or intended use rather than its actual value", "Keeping a budget spreadsheet", "Calculating compound interest"], correct: 1, explanation: "Mental accounting leads people to treat money differently based on where it came from. A $1,000 tax refund might be 'spent freely' while $1,000 from salary is saved — even though a dollar is a dollar.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 70, question: "What is FOMO and how does it affect investment decisions?", options: ["A new type of ETF", "Fear Of Missing Out — it drives investors to chase hot stocks and trends at their peak", "A financial planning method", "A type of market order"], correct: 1, explanation: "FOMO causes investors to buy into hot stocks, crypto, or trends at their peak because everyone else is profiting. By the time FOMO kicks in, the easy gains are usually gone and the risk of buying high is at its greatest.", difficulty: "beginner", topic: "behavioral", learnLink: "behavioral" },
  { id: 71, question: "What is recency bias?", options: ["Preferring recently listed stocks", "Overweighting recent events and assuming they'll continue into the future", "A strategy for short-term trading", "Reading only the latest financial news"], correct: 1, explanation: "Recency bias causes investors to assume recent trends will continue. After a bull market, people become overconfident. After a crash, they assume stocks will never recover. Both reactions are usually wrong.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 72, question: "What is overconfidence bias?", options: ["Having confidence in index funds", "Overestimating your ability to predict market movements or pick winning stocks", "Being confident in your financial plan", "A type of investment strategy"], correct: 1, explanation: "Overconfidence bias leads investors to trade too frequently, take excessive risk, and underestimate potential losses. Studies show overconfident traders earn 2-4% less annually than the market average due to excessive trading.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },

  // ── GENERAL INVESTING ──────────────────────────────
  { id: 3, question: "What is compound interest?", options: ["Interest only on your original investment", "Interest on interest plus principal", "A fixed interest rate", "Interest paid monthly"], correct: 1, explanation: "Compound interest means you earn returns on your returns — it's the most powerful force in wealth building!", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 19, question: "What is the Rule of 72?", options: ["Invest at least 72% of income", "Divide 72 by return rate to estimate doubling time", "Never invest more than $72,000", "A tax code section"], correct: 1, explanation: "At 8% annual returns, 72 ÷ 8 = 9 years to double your money. At 12%, just 6 years. It's a quick mental math tool!", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 23, question: "What does 'liquidity' mean in investing?", options: ["How much cash you have", "How easily an asset can be converted to cash", "The interest rate on a bond", "A type of mutual fund"], correct: 1, explanation: "Liquidity refers to how quickly and easily you can buy or sell an investment without significantly affecting its price.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 27, question: "What is dollar-weighted return?", options: ["Total return divided by years", "Return that accounts for timing and size of cash flows", "The return in US dollars only", "Average annual return"], correct: 1, explanation: "Dollar-weighted return (IRR) accounts for when you add or withdraw money, giving a personal performance measure.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 73, question: "What is the Sharpe ratio?", options: ["A company's profit margin", "A measure of risk-adjusted return relative to a risk-free asset", "The ratio of stocks to bonds", "A type of financial statement"], correct: 1, explanation: "The Sharpe ratio measures how much excess return you receive for the extra volatility you endure. A higher Sharpe ratio means better risk-adjusted performance. Values above 1 are considered good.", difficulty: "advanced", topic: "general", learnLink: "diversification" },
  { id: 74, question: "What is the difference between nominal and real returns?", options: ["Nominal is after tax, real is before tax", "Nominal is before inflation, real is after inflation", "They are the same thing", "Real returns are always higher"], correct: 1, explanation: "Nominal returns don't account for inflation. Real returns subtract inflation. If your portfolio gains 10% but inflation is 3%, your real return is approximately 7%. Always think in real terms for long-term planning.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 75, question: "What is portfolio rebalancing?", options: ["Selling all investments", "Adjusting holdings back to target allocation percentages", "Adding new stocks to a portfolio", "Closing your brokerage account"], correct: 1, explanation: "Rebalancing means selling what's grown beyond your target and buying what's shrunk, systematically buying low and selling high. Most experts recommend rebalancing annually or when allocations drift 5%+ from targets.", difficulty: "intermediate", topic: "general", learnLink: "diversification" },
  { id: 76, question: "What is a 3-fund portfolio?", options: ["A portfolio with only 3 stocks", "A simple portfolio with US stocks, international stocks, and bonds via 3 low-cost index funds", "A portfolio that changes 3 times per year", "A portfolio with 3 different brokerages"], correct: 1, explanation: "The 3-fund portfolio (e.g., VTI + VXUS + BND) provides broad diversification across the entire global market with minimal cost and complexity. It's recommended by Bogleheads and financial experts alike.", difficulty: "beginner", topic: "general", learnLink: "diversification" },
  { id: 77, question: "What does 'buying on margin' mean?", options: ["Buying stocks at a discount", "Borrowing money from a broker to purchase investments", "Buying stocks in small quantities", "Buying stocks at the market close"], correct: 1, explanation: "Buying on margin means borrowing money from your brokerage to invest. It amplifies both gains and losses. If your investments drop enough, you'll face a 'margin call' requiring you to deposit more funds or have positions sold.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 78, question: "What is the difference between systematic and unsystematic risk?", options: ["They are the same", "Systematic affects the entire market and can't be diversified away; unsystematic affects individual companies and can be", "Systematic is lower risk", "Unsystematic affects the entire market"], correct: 1, explanation: "Systematic risk (market risk) affects all investments — recessions, interest rate changes. Unsystematic risk is specific to a company or industry. Diversification eliminates unsystematic risk but not systematic risk.", difficulty: "advanced", topic: "general", learnLink: "diversification" },
  { id: 79, question: "What is an IPO?", options: ["Internal Portfolio Optimization", "Initial Public Offering — when a company first sells shares to the public", "Investment Protection Order", "Index Performance Overview"], correct: 1, explanation: "An IPO is when a private company first offers its shares to the public on a stock exchange. While IPOs generate excitement, studies show they often underperform the broader market in their first few years.", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 80, question: "What is a stock buyback?", options: ["A company buying its competitors", "When a company repurchases its own shares from the market", "An investor returning shares", "A type of dividend payment"], correct: 1, explanation: "A stock buyback is when a company uses its cash to buy back its own shares, reducing the share count. This increases EPS and each remaining share's ownership percentage. It's an alternative to paying dividends.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 81, question: "What is the difference between a Roth IRA and a brokerage account?", options: ["There is no difference", "Roth IRA has tax-free growth but contribution limits and withdrawal rules; brokerage accounts have no limits but gains are taxed", "Brokerage accounts have tax-free growth", "Roth IRA has no contribution limits"], correct: 1, explanation: "A Roth IRA offers tax-free growth and withdrawals in retirement but has annual contribution limits ($7,000 in 2026) and income eligibility rules. Brokerage accounts have no limits but you pay capital gains tax on profits.", difficulty: "beginner", topic: "general", learnLink: "retirement" },

  // ── INDEX FUNDS ──────────────────────────────────────
  { id: 15, question: "What is an index fund?", options: ["A fund managed by a financial advisor", "A fund that tracks a market index passively", "A fund only for advanced investors", "A high-risk speculative fund"], correct: 1, explanation: "Index funds passively track market benchmarks like the S&P 500. They have the lowest fees and outperform most active managers over time.", difficulty: "beginner", topic: "index-funds", learnLink: "index-funds" },

  // ── DIVERSIFICATION ──────────────────────────────────
  { id: 4, question: "What is diversification?", options: ["Putting all money in one stock", "Spreading investments across different assets", "Only investing in bonds", "Timing the market"], correct: 1, explanation: "Diversification reduces risk by spreading your money across different investments. Don't put all eggs in one basket!", difficulty: "beginner", topic: "diversification", learnLink: "diversification" },
  { id: 17, question: "What does 'asset allocation' mean?", options: ["Owning only one type of investment", "How you divide money among different asset types", "Selling all your assets", "A government regulation"], correct: 1, explanation: "Asset allocation — your mix of stocks, bonds, and other assets — determines about 90% of your portfolio's performance variability.", difficulty: "intermediate", topic: "diversification", learnLink: "diversification" },
  { id: 29, question: "What is rebalancing a portfolio?", options: ["Selling all investments", "Adjusting holdings back to target allocation", "Only buying bonds", "Switching brokers"], correct: 1, explanation: "Rebalancing means selling what's grown beyond your target and buying what's shrunk, systematically buying low and selling high.", difficulty: "intermediate", topic: "diversification", learnLink: "diversification" },

  // ── DCA ──────────────────────────────────────────
  { id: 10, question: "What is dollar-cost averaging?", options: ["Buying at the lowest price", "Investing a fixed amount at regular intervals", "Only investing in dollars", "Averaging your returns"], correct: 1, explanation: "Dollar-cost averaging means investing the same amount regularly, regardless of price. It removes emotion from investing!", difficulty: "beginner", topic: "dca", learnLink: "dca" },

  // ── DIVIDENDS ──────────────────────────────────────
  { id: 16, question: "What is a dividend?", options: ["A fee you pay to own stocks", "A cash payment from a company to shareholders", "A tax on investment gains", "A type of bond"], correct: 1, explanation: "Dividends are portions of company profits distributed to shareholders. Reinvesting them supercharges compound growth.", difficulty: "beginner", topic: "dividends", learnLink: "dividends" },

  // ── REITs ──────────────────────────────────────────
  { id: 9, question: "What is a REIT required to distribute as dividends?", options: ["25% of income", "50% of income", "75% of income", "90% of income"], correct: 3, explanation: "REITs must distribute at least 90% of their taxable income as dividends, making them great for income investors.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },
  { id: 82, question: "What is Funds From Operations (FFO) for a REIT?", options: ["The REIT's stock price", "A measure of a REIT's operating performance, similar to earnings but adjusted for real estate", "The total rent collected", "The REIT's expense ratio"], correct: 1, explanation: "FFO is the key profitability metric for REITs. It takes net income, adds back depreciation (which is non-cash), and subtracts gains from property sales. It gives a clearer picture of REIT cash flow than standard earnings.", difficulty: "advanced", topic: "reits", learnLink: "reits" },
  { id: 83, question: "What is the difference between equity REITs and mortgage REITs?", options: ["They are the same", "Equity REITs own properties; mortgage REITs invest in real estate debt/mortgages", "Mortgage REITs own properties", "Equity REITs only invest in stocks"], correct: 1, explanation: "Equity REITs own and operate income-producing real estate. Mortgage REITs (mREITs) invest in mortgages and mortgage-backed securities. Equity REITs are generally less volatile and more popular with long-term investors.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },
  { id: 84, question: "What is cap rate in real estate investing?", options: ["The maximum investment amount", "Net operating income divided by property value, expressing the rate of return", "The interest rate on a mortgage", "The property tax rate"], correct: 1, explanation: "Cap rate (capitalization rate) = Net Operating Income ÷ Property Value. A property generating $50,000 NOI with a $500,000 value has a 10% cap rate. Higher cap rates suggest higher returns but also higher risk.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },
  { id: 85, question: "How do REITs provide inflation protection?", options: ["They don't", "Property values and rents typically rise with inflation, increasing REIT income", "They are indexed to the CPI", "They hold Treasury bonds"], correct: 1, explanation: "REITs offer a natural inflation hedge because property values and rents generally increase with inflation. As prices rise, landlords can raise rents, which flows through to higher REIT dividends over time.", difficulty: "intermediate", topic: "reits", learnLink: "reits" },

  // ── OPTIONS ──────────────────────────────────────────
  { id: 20, question: "What is a covered call?", options: ["Buying a stock secretly", "Selling a call option on stock you own", "Calling your broker for advice", "A type of insurance policy"], correct: 1, explanation: "A covered call generates income by selling the right for someone to buy your stock at a higher price. It's one of the simplest options strategies.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 86, question: "What is 'theta' in options trading?", options: ["The option's price", "The rate at which an option loses value as time passes", "The option's strike price", "The underlying stock's volatility"], correct: 1, explanation: "Theta measures time decay — how much value an option loses each day. Options are 'wasting assets' that lose value as expiration approaches. This is why selling options (being short theta) can be a consistent income strategy.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 87, question: "What does 'in the money' mean for a call option?", options: ["The option is profitable to exercise", "The stock price is above the option's strike price", "The option has expired", "The option is free"], correct: 1, explanation: "A call option is 'in the money' when the current stock price is above the strike price. For example, a $100 call is ITM when the stock trades at $110. This means the option has intrinsic value.", difficulty: "intermediate", topic: "options", learnLink: "options" },
  { id: 88, question: "What is a protective put?", options: ["A type of savings account", "Buying a put option on stock you own to limit downside risk", "Putting money into a safe", "A bond investment strategy"], correct: 1, explanation: "A protective put is like insurance for your stock position. You buy a put option that gives you the right to sell your shares at the strike price, limiting your maximum loss if the stock drops significantly.", difficulty: "advanced", topic: "options", learnLink: "options" },
  { id: 89, question: "What is implied volatility?", options: ["The actual volatility of a stock's past prices", "The market's expectation of future price movement, reflected in option prices", "The average daily trading volume", "The beta of a stock"], correct: 1, explanation: "Implied volatility (IV) represents the market's forecast of how much a stock's price will move. Higher IV means more expensive options. IV typically spikes before earnings reports and during market uncertainty.", difficulty: "advanced", topic: "options", learnLink: "options" },

  // ── HEDGE FUNDS ──────────────────────────────────────
  { id: 18, question: "What is a hedge fund?", options: ["A low-cost index fund", "A private fund using advanced strategies for wealthy investors", "A government savings program", "A type of insurance"], correct: 1, explanation: "Hedge funds use complex strategies and charge high fees. Most underperform simple index funds after fees — even Warren Buffett says so.", difficulty: "advanced", topic: "hedge-funds", learnLink: "hedge-funds" },

  // ── ADDITIONAL GENERAL ──────────────────────────────
  { id: 90, question: "What is a fiduciary?", options: ["A type of investment", "A financial professional legally required to act in your best interest", "A type of tax", "A government regulator"], correct: 1, explanation: "A fiduciary is legally obligated to put your interests first. Not all financial advisors are fiduciaries — many work on commission. Always ask if your advisor is a fiduciary before hiring them.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 91, question: "What is the efficient market hypothesis?", options: ["Markets always go up", "Stock prices reflect all available information, making it difficult to consistently outperform", "Efficient markets have lower fees", "A strategy for timing the market"], correct: 1, explanation: "The EMH suggests that stock prices already incorporate all known information, making it nearly impossible to consistently 'beat the market' through stock picking or market timing. This is a key argument for index investing.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 92, question: "What does DRIP stand for?", options: ["Daily Return Investment Plan", "Dividend Reinvestment Plan", "Debt Reduction Investment Program", "Dynamic Risk Investment Portfolio"], correct: 1, explanation: "A Dividend Reinvestment Plan (DRIP) automatically uses your dividend payments to purchase additional shares. Over long periods, DRIP can significantly boost total returns through compound growth.", difficulty: "beginner", topic: "dividends", learnLink: "dividends" },
  { id: 93, question: "What is a target-date fund?", options: ["A fund that targets high returns", "A fund that automatically adjusts its stock/bond mix as you approach a target retirement year", "A fund with a guaranteed return", "A fund that expires on a set date"], correct: 1, explanation: "Target-date funds (like Vanguard Target Retirement 2050) start with an aggressive allocation and gradually shift toward bonds as the target date approaches. They're a 'set it and forget it' solution for retirement investing.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 94, question: "What is a financial advisor's 'fee-only' model?", options: ["They charge no fees", "They earn fees directly from clients rather than commissions on products they sell", "They only charge for initial consultations", "They charge based on your net worth"], correct: 1, explanation: "Fee-only advisors charge a flat fee, hourly rate, or percentage of AUM — but don't earn commissions from selling you products. This eliminates conflicts of interest and aligns their incentives with yours.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 95, question: "What is dollar-cost averaging's main psychological benefit?", options: ["It guarantees higher returns", "It removes the stress of trying to time the market by making investing automatic", "It eliminates all risk", "It avoids all taxes"], correct: 1, explanation: "DCA's greatest benefit may be psychological: by investing a fixed amount on a regular schedule, you avoid the anxiety of trying to pick the 'perfect' time to invest. This consistency leads to better long-term results than trying to time the market.", difficulty: "beginner", topic: "dca", learnLink: "dca" },
  { id: 96, question: "What does 'time in the market' beat?", options: ["Dollar-cost averaging", "Timing the market", "Diversification", "Rebalancing"], correct: 1, explanation: "The saying 'time in the market beats timing the market' emphasizes that staying invested consistently produces better results than trying to buy low and sell high. Missing just the 10 best trading days in a 20-year period can cut your returns in half.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 97, question: "What is a Dividend Aristocrat?", options: ["A wealthy dividend investor", "An S&P 500 company that has increased its dividend for 25+ consecutive years", "A type of preferred stock", "A dividend ETF"], correct: 1, explanation: "Dividend Aristocrats are elite S&P 500 companies that have raised their dividend every year for at least 25 years. Examples include Johnson & Johnson, Procter & Gamble, and Coca-Cola.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
  { id: 98, question: "What is a bear market rally?", options: ["A permanent market recovery", "A temporary price increase during an overall downtrend", "A celebration of market bears", "A new bull market beginning"], correct: 1, explanation: "A bear market rally is a temporary bounce in stock prices during a broader decline. They can be deceptive — prices may rise 10-20% before resuming the downtrend, trapping investors who think the bottom is in.", difficulty: "intermediate", topic: "general", learnLink: "stocks" },
  { id: 99, question: "What is a stop-loss order?", options: ["An order to stop trading entirely", "An order that automatically sells a stock when it drops to a specified price", "An order to prevent losses from taxes", "An order to buy stocks at a discount"], correct: 1, explanation: "A stop-loss order triggers a market sell order when a stock falls to your specified price. It helps limit downside risk, but can also sell you out of temporary dips. Many long-term investors prefer to avoid them.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 100, question: "What is dollar-cost averaging NOT good for?", options: ["Reducing emotional investing", "Building long-term wealth", "Maximizing returns when you have a lump sum and a long time horizon", "Creating a savings habit"], correct: 2, explanation: "When you have a lump sum to invest and a long time horizon, studies show lump-sum investing outperforms DCA about 67% of the time because markets tend to rise over time. DCA's strength is reducing regret and emotional risk.", difficulty: "advanced", topic: "dca", learnLink: "dca" },
  { id: 101, question: "What is sequence-of-returns risk?", options: ["The risk of choosing the wrong investment sequence", "The risk that poor returns early in retirement can permanently damage your portfolio", "The risk of rebalancing too often", "The risk of investing in sequential IPOs"], correct: 1, explanation: "Sequence-of-returns risk is critical for retirees: if you experience large losses early in retirement while withdrawing funds, your portfolio may never recover. This is why retirees should hold a cash buffer and reduce equity exposure.", difficulty: "advanced", topic: "retirement", learnLink: "retirement" },
  { id: 102, question: "What is the difference between growth and income investing?", options: ["They are the same strategy", "Growth focuses on capital appreciation; income focuses on dividends and interest", "Income investing is riskier", "Growth investing pays dividends"], correct: 1, explanation: "Growth investing targets companies expected to increase in value (capital appreciation), while income investing focuses on assets that produce regular cash flow (dividends, bond interest). Many portfolios combine both.", difficulty: "beginner", topic: "general", learnLink: "dividends" },
  { id: 103, question: "What is a 529 plan?", options: ["A type of retirement account", "A tax-advantaged education savings plan", "A type of 401k", "A health savings account"], correct: 1, explanation: "A 529 plan allows you to save and invest for education expenses with tax-free growth and tax-free withdrawals for qualified education costs. Many states also offer a state tax deduction for contributions.", difficulty: "beginner", topic: "general", learnLink: "taxes" },
  { id: 104, question: "What is the primary advantage of index investing?", options: ["Guaranteed returns", "Low costs, broad diversification, and historically beating most active managers", "No risk of loss", "Tax-free growth"], correct: 1, explanation: "Index funds offer the trifecta of investing advantages: ultra-low fees (0.03-0.10%), instant diversification across hundreds or thousands of companies, and performance that beats 90%+ of active managers over 15+ year periods.", difficulty: "beginner", topic: "index-funds", learnLink: "index-funds" },
  { id: 105, question: "What is a correction in the stock market?", options: ["When a stock's price is adjusted for errors", "A decline of 10-20% from recent highs", "A bull market surge", "When trading is halted"], correct: 1, explanation: "A market correction is a 10-20% decline from recent highs. Corrections are normal and happen roughly once a year on average. They're different from bear markets (20%+ decline) and crashes (sudden steep drops).", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 106, question: "What is an emergency fund and how much should you have?", options: ["A stock portfolio for emergencies", "3-6 months of expenses saved in a liquid, accessible account", "An insurance policy", "A credit card for emergencies"], correct: 1, explanation: "An emergency fund is 3-6 months of living expenses kept in a high-yield savings account or money market fund. It prevents you from selling investments or taking on debt when unexpected expenses arise.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 107, question: "What is the difference between active and passive investing?", options: ["Active is for retirement, passive is for taxable accounts", "Active tries to beat the market through selection; passive aims to match the market via index funds", "Passive investing requires more work", "Active investing always has lower fees"], correct: 1, explanation: "Active investing involves selecting individual securities or timing the market to try to outperform a benchmark. Passive investing tracks an index. After fees, over 90% of active managers underperform their benchmark over 15+ years.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 108, question: "What is a money market fund?", options: ["A fund that trades foreign currencies", "A low-risk fund that invests in short-term, high-quality debt securities", "A stock market index fund", "A hedge fund"], correct: 1, explanation: "Money market funds invest in short-term government and corporate debt. They aim to maintain a $1 NAV while paying interest. They're used for parking cash short-term with slightly higher returns than a savings account.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 109, question: "What is dollar-cost averaging into a declining market?", options: ["A mistake to avoid", "Actually beneficial because you buy more shares at lower prices", "The same as timing the market", "Always a bad strategy"], correct: 1, explanation: "DCA shines in declining markets: your fixed dollar amount buys more shares when prices are low. When the market eventually recovers, those extra shares amplify your gains significantly.", difficulty: "intermediate", topic: "dca", learnLink: "dca" },
  { id: 110, question: "What is the FIRE movement?", options: ["A type of investing strategy", "Financial Independence, Retire Early — aggressive saving and investing to retire decades before traditional age", "A government program", "A high-frequency trading strategy"], correct: 1, explanation: "FIRE stands for Financial Independence, Retire Early. Practitioners save 50-70% of their income, invest heavily in index funds, and aim to build a portfolio 25x their annual expenses (enabling the 4% withdrawal rule).", difficulty: "intermediate", topic: "general", learnLink: "retirement" },
  { id: 111, question: "What is the price-to-book (P/B) ratio?", options: ["Stock price divided by annual revenue", "Stock price divided by book value per share", "The cost of the company's headquarters", "The share price at IPO"], correct: 1, explanation: "P/B ratio compares a stock's market value to its book value (assets minus liabilities). A P/B under 1 might indicate an undervalued stock. Value investors often look for low P/B ratios combined with strong fundamentals.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 112, question: "What is dollar-weighted vs time-weighted return?", options: ["They measure the same thing", "Dollar-weighted reflects your personal performance (including timing of cash flows); time-weighted removes cash flow effects", "Time-weighted is always higher", "Dollar-weighted is only for bonds"], correct: 1, explanation: "Time-weighted return measures the fund's performance irrespective of cash flows (good for evaluating managers). Dollar-weighted (IRR) reflects your personal experience, including when you added or withdrew money.", difficulty: "advanced", topic: "general", learnLink: "index-funds" },
  { id: 113, question: "What is a CD (Certificate of Deposit)?", options: ["A type of stock certificate", "A bank savings product with a fixed term and guaranteed interest rate", "A type of bond", "A mutual fund category"], correct: 1, explanation: "CDs offer a guaranteed interest rate for a fixed period (3 months to 5 years). They're FDIC-insured but your money is locked up — early withdrawal triggers a penalty. CD laddering spreads out maturities for better flexibility.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 114, question: "What is a stock's dividend payout ratio?", options: ["The stock's market cap", "The percentage of earnings paid out as dividends", "The annual dividend amount", "The number of times dividends are paid per year"], correct: 1, explanation: "Payout ratio = dividends per share ÷ earnings per share. A 40% payout ratio means the company distributes 40% of earnings as dividends. Very high payout ratios (>80%) may be unsustainable.", difficulty: "intermediate", topic: "dividends", learnLink: "dividends" },
  { id: 115, question: "What is a robo-advisor?", options: ["A robot that trades stocks", "An automated investment platform that builds and manages a portfolio based on your goals and risk tolerance", "A type of hedge fund", "AI-powered stock picker"], correct: 1, explanation: "Robo-advisors like Betterment and Wealthfront create diversified portfolios using algorithms, automatically rebalance, and tax-loss harvest. They typically charge 0.25% per year — less than human advisors but more than DIY index investing.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 116, question: "What is a SPAC?", options: ["Special Purpose Acquisition Company — a shell company that raises money through an IPO to acquire a private company", "Stock Price Automatic Calculator", "Standard Portfolio Asset Class", "A type of index fund"], correct: 0, explanation: "SPACs are 'blank check' companies that IPO with no existing business, then use the raised funds to acquire a private company, taking it public without a traditional IPO. They became popular in 2020-2021 but have had mixed results for investors.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 117, question: "What does 'catching a falling knife' mean?", options: ["A skilled trading technique", "Buying a rapidly declining stock hoping to catch the bottom, which is very risky", "A guaranteed profit strategy", "Setting a stop-loss order"], correct: 1, explanation: "Catching a falling knife means trying to buy a stock during a steep decline. It's dangerous because there's no way to know when the drop will end. Experienced investors often wait for a 'base' to form before buying.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 118, question: "What is a stock's 52-week high/low?", options: ["The predicted range for the next year", "The highest and lowest prices the stock has traded at in the past year", "The range of analyst price targets", "The IPO price and current price"], correct: 1, explanation: "The 52-week high and low shows the price range over the past year. Stocks near their 52-week high might indicate strength (or overvaluation), while those near the low might signal weakness (or a buying opportunity).", difficulty: "beginner", topic: "stocks", learnLink: "stocks" },
  { id: 119, question: "What is the S&P 500?", options: ["A savings plan with 500% return", "An index tracking 500 of the largest U.S. public companies", "A retirement account type", "500 international companies"], correct: 1, explanation: "The S&P 500 is a stock market index of 500 large U.S. companies, representing about 80% of total U.S. stock market value. It's the most widely followed benchmark for U.S. equity performance.", difficulty: "beginner", topic: "index-funds", learnLink: "index-funds" },
  { id: 120, question: "What is a prospectus?", options: ["A stock price prediction", "A legal document describing an investment's objectives, risks, fees, and strategy", "A financial advisor's resume", "A type of portfolio"], correct: 1, explanation: "A prospectus is a mandatory legal document that details a fund's investment objectives, risks, fees, and past performance. You should review it before investing, paying special attention to the expense ratio and investment strategy.", difficulty: "beginner", topic: "etfs", learnLink: "etfs" },
  { id: 121, question: "What is the difference between growth and value investing styles?", options: ["They produce identical returns", "Growth invests in fast-growing companies; value looks for underpriced companies based on fundamentals", "Growth is safer", "Value investing is obsolete"], correct: 1, explanation: "Growth investors seek companies with above-average revenue/earnings growth (higher P/E ratios). Value investors look for stocks trading below intrinsic value (lower P/E). Historically, value has slightly outperformed, but both have merit.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 122, question: "What is an I-Bond?", options: ["A type of corporate bond", "A U.S. government savings bond with an interest rate that adjusts for inflation", "An international bond fund", "A bond issued by insurance companies"], correct: 1, explanation: "I-Bonds are U.S. savings bonds with a rate that combines a fixed rate and an inflation-adjusted rate (updated every 6 months). They're one of the safest inflation hedges available, though limited to $10,000/year per person.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 123, question: "What does 'buy and hold' mean?", options: ["Buy stocks and sell within a day", "Purchasing investments and holding them for the long term regardless of short-term fluctuations", "A type of limit order", "Buying on margin"], correct: 1, explanation: "Buy and hold is a passive strategy of purchasing quality investments and holding them for years or decades, ignoring short-term volatility. It benefits from compound growth, lower taxes, and reduced transaction costs.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 124, question: "What is a high-yield savings account (HYSA)?", options: ["A stock trading account", "A savings account offering significantly higher interest rates than traditional savings accounts", "A type of IRA", "A certificate of deposit"], correct: 1, explanation: "HYSAs (often from online banks) offer interest rates several times higher than traditional bank savings accounts. They're FDIC-insured and ideal for emergency funds and short-term savings goals.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 125, question: "What is free cash flow?", options: ["Money given away by companies", "Cash generated by a business after accounting for capital expenditures", "The stock's current price", "Dividends paid to shareholders"], correct: 1, explanation: "Free cash flow = operating cash flow minus capital expenditures. It represents the cash a company generates after maintaining/expanding its asset base. Strong FCF indicates a healthy business that can pay dividends, buy back shares, or invest in growth.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 126, question: "What is the Buffett Indicator?", options: ["Warren Buffett's personal net worth", "Total stock market capitalization divided by GDP — a measure of overall market valuation", "Berkshire Hathaway's stock price", "An earnings ratio"], correct: 1, explanation: "The Buffett Indicator (total market cap / GDP) is Warren Buffett's favorite gauge of market valuation. He called it 'probably the best single measure of where valuations stand at any given moment.' Readings above 100% suggest overvaluation.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 127, question: "What is a savings rate and why is it important?", options: ["The interest rate on savings accounts", "The percentage of your income that you save and invest — the most controllable factor in wealth building", "The rate of inflation", "The rate of return on investments"], correct: 1, explanation: "Your savings rate = (income - spending) / income. A 20% savings rate is good; 50%+ enables early retirement. Unlike market returns (which you can't control), your savings rate is entirely within your control.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 128, question: "What is tax-deferred growth?", options: ["Growth that is never taxed", "Investment growth that isn't taxed until you withdraw the money", "Growth only in tax-free accounts", "A type of capital gain"], correct: 1, explanation: "Tax-deferred growth means your investments compound without being reduced by annual taxes. Traditional IRAs and 401(k)s offer this benefit — you only pay taxes when you withdraw in retirement, potentially at a lower tax bracket.", difficulty: "beginner", topic: "taxes", learnLink: "taxes" },
  { id: 129, question: "What is a margin of safety in investing?", options: ["The amount of margin in your account", "Buying an investment at a significant discount to its estimated intrinsic value", "The percentage of bonds in your portfolio", "A stop-loss percentage"], correct: 1, explanation: "Coined by Benjamin Graham, margin of safety means buying investments well below their calculated intrinsic value. This buffer protects against errors in analysis and unforeseen events. It's the foundation of value investing.", difficulty: "advanced", topic: "general", learnLink: "stocks" },
  { id: 130, question: "What percentage of actively managed funds underperform their benchmark over 15 years?", options: ["About 30%", "About 50%", "About 70%", "Over 90%"], correct: 3, explanation: "According to SPIVA research, over 90% of actively managed U.S. large-cap funds underperform the S&P 500 over 15-year periods. This is the strongest argument for passive index fund investing.", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },
  { id: 131, question: "What is asset correlation?", options: ["Assets that have the same price", "How closely two investments move together — low correlation improves diversification", "The total number of assets in your portfolio", "A measure of asset quality"], correct: 1, explanation: "Correlation ranges from -1 (move opposite) to +1 (move together). Combining assets with low or negative correlation reduces overall portfolio volatility without sacrificing expected returns. This is the magic of diversification.", difficulty: "advanced", topic: "diversification", learnLink: "diversification" },
  { id: 132, question: "What is the difference between a traditional brokerage and a discount brokerage?", options: ["They are the same", "Traditional offers full advisory services with higher fees; discount offers self-directed trading with lower fees", "Discount brokerages have worse execution", "Traditional brokerages are always better"], correct: 1, explanation: "Traditional brokerages (like Morgan Stanley) provide personal financial advice but charge higher fees. Discount brokerages (like Fidelity, Schwab, Vanguard) offer self-directed trading with minimal commissions — most charge $0 per stock trade.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 133, question: "What is a market correction vs. a bear market vs. a crash?", options: ["They all mean the same thing", "Correction: 10-20% decline; Bear market: 20%+ decline; Crash: sudden, severe drop", "Correction is worse than a bear market", "Crashes only happen once per century"], correct: 1, explanation: "Corrections (10-20% drops) happen roughly yearly. Bear markets (20%+) occur every 3-5 years. Crashes are sudden, steep declines (like 2008 or March 2020). All are normal parts of the market cycle.", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 134, question: "What is a sector rotation strategy?", options: ["Rotating your portfolio every month", "Shifting investments between market sectors based on the economic cycle", "Only investing in one sector", "A type of index fund"], correct: 1, explanation: "Sector rotation involves shifting allocations between economic sectors based on where we are in the business cycle. For example, healthcare and utilities tend to outperform in recessions, while tech and financials outperform in expansions.", difficulty: "advanced", topic: "general", learnLink: "diversification" },
  { id: 135, question: "What is the 'wealth effect'?", options: ["A strategy for getting rich", "When rising asset values make people feel wealthier and spend more, even without selling", "The effect of compound interest", "A type of market manipulation"], correct: 1, explanation: "The wealth effect describes how people spend more when they see their portfolio or home values rising, even though they haven't sold anything. This paper wealth creates a psychological sense of prosperity that influences economic behavior.", difficulty: "intermediate", topic: "behavioral", learnLink: "behavioral" },
  { id: 136, question: "What is net worth and how do you calculate it?", options: ["Your annual salary", "Total assets minus total liabilities", "The value of your stock portfolio", "Your credit score"], correct: 1, explanation: "Net worth = everything you own (assets: savings, investments, property) minus everything you owe (liabilities: debt, loans, mortgage). It's the single best measure of your financial health and progress over time.", difficulty: "beginner", topic: "general", learnLink: "retirement" },
  { id: 137, question: "What is a commodity?", options: ["A type of stock", "A basic raw material (gold, oil, wheat) that can be traded on exchanges", "A type of bond", "A technology company"], correct: 1, explanation: "Commodities are raw materials like gold, oil, natural gas, and agricultural products. They can serve as inflation hedges and portfolio diversifiers, but they don't produce earnings or dividends — their value comes purely from supply and demand.", difficulty: "beginner", topic: "general", learnLink: "diversification" },
  { id: 138, question: "What is the CAPE ratio?", options: ["A measure of a company's capital expenditures", "Cyclically Adjusted Price-to-Earnings ratio — uses 10 years of inflation-adjusted earnings to value the market", "A type of bond yield", "A trading volume metric"], correct: 1, explanation: "The CAPE ratio (Shiller P/E) divides the S&P 500 price by the average of 10 years of inflation-adjusted earnings. It smooths out short-term fluctuations and is one of the best long-term predictors of future market returns.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 139, question: "What is a bond ladder?", options: ["A way to climb in bond ratings", "A strategy of buying bonds with staggered maturity dates to manage interest rate risk", "A list of the best bonds to buy", "A type of corporate bond"], correct: 1, explanation: "A bond ladder involves buying bonds that mature at different intervals (e.g., 1, 2, 3, 4, 5 years). As each matures, you reinvest at current rates. This provides regular income, reduces interest rate risk, and maintains liquidity.", difficulty: "intermediate", topic: "bonds", learnLink: "bonds" },
  { id: 140, question: "What is the difference between saving and investing?", options: ["They are the same thing", "Saving preserves capital with low risk; investing grows capital with higher risk and potential returns", "Investing is safer than saving", "Saving always earns more than investing"], correct: 1, explanation: "Saving (HYSA, CDs) preserves your money with minimal risk but often loses purchasing power to inflation. Investing (stocks, bonds) carries risk but historically grows wealth significantly faster — the S&P 500 averages ~10% annually vs. ~4-5% for savings.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 141, question: "What is a preferred stock?", options: ["The most popular stock on an exchange", "A hybrid security with bond-like dividends and stock-like ownership, paid before common shareholders", "A stock with voting rights", "A stock recommended by analysts"], correct: 1, explanation: "Preferred stocks pay fixed dividends (like bonds) and get priority over common stockholders in dividend payments and liquidation. However, they usually lack voting rights and have limited upside potential compared to common stocks.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 142, question: "What is a stock's book value?", options: ["The price listed in a stock book", "The net asset value of a company (total assets minus total liabilities) divided by shares outstanding", "The original IPO price", "The highest price ever traded"], correct: 1, explanation: "Book value per share = (total assets - total liabilities) / shares outstanding. It represents the theoretical liquidation value. Value investors look for stocks trading below book value (P/B < 1) as potential bargains.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 143, question: "What is a recession?", options: ["A stock market crash", "Two consecutive quarters of declining GDP", "A rise in unemployment", "A period of high inflation"], correct: 1, explanation: "A recession is commonly defined as two consecutive quarters of declining GDP. Recessions typically bring higher unemployment, lower corporate earnings, and falling stock prices — but they also create buying opportunities for long-term investors.", difficulty: "beginner", topic: "general", learnLink: "stocks" },
  { id: 144, question: "What is a yield trap?", options: ["A high-yield bond", "A stock with an unusually high dividend yield that may indicate financial distress or an upcoming dividend cut", "A guaranteed income investment", "A type of bond fund"], correct: 1, explanation: "A yield trap occurs when a stock's dividend yield is very high because its price has plummeted — often due to deteriorating business fundamentals. The high yield attracts income investors, but a dividend cut often follows, causing further price declines.", difficulty: "advanced", topic: "dividends", learnLink: "dividends" },
  { id: 145, question: "What is the total stock market vs. the S&P 500?", options: ["They are identical", "Total stock market includes small and mid-cap stocks in addition to the large-caps in the S&P 500", "S&P 500 is larger", "Total stock market only includes tech stocks"], correct: 1, explanation: "The total stock market (tracked by VTI) includes ~4,000 stocks across all sizes, while the S&P 500 only includes 500 large-cap companies. The difference in long-term returns is small, but the total market provides slightly more diversification.", difficulty: "intermediate", topic: "index-funds", learnLink: "index-funds" },
  { id: 146, question: "What is tax-advantaged investing?", options: ["Investing only in stocks", "Using account types (IRA, 401k, HSA) that provide tax benefits to boost long-term returns", "Avoiding all taxes on investments", "Only investing in municipal bonds"], correct: 1, explanation: "Tax-advantaged investing uses special account types that offer tax benefits: Traditional (tax-deferred growth), Roth (tax-free growth), and HSA (triple tax benefit). Maximizing these accounts before taxable investing is a key wealth-building strategy.", difficulty: "beginner", topic: "taxes", learnLink: "taxes" },
  { id: 147, question: "What is a treasury bond?", options: ["A corporate debt instrument", "A U.S. government debt security with a maturity of 20-30 years, considered the safest investment", "A type of stock", "A bond issued by local governments"], correct: 1, explanation: "Treasury bonds are long-term U.S. government debt securities backed by the 'full faith and credit' of the U.S. government. They're considered virtually risk-free for default and serve as a benchmark for all other interest rates.", difficulty: "beginner", topic: "bonds", learnLink: "bonds" },
  { id: 148, question: "What is herd mentality in investing?", options: ["Investing in agricultural stocks", "Following the crowd's investment decisions instead of doing your own research", "A diversification strategy", "Investing in a group account"], correct: 1, explanation: "Herd mentality causes investors to follow what everyone else is doing — buying during euphoria and selling during panic. This is how bubbles form and crash. Successful investors often do the opposite of the herd.", difficulty: "beginner", topic: "behavioral", learnLink: "behavioral" },
  { id: 149, question: "What is the power of compound growth over 30 years?", options: ["$500/month at 10% grows to about $100,000", "$500/month at 10% grows to about $500,000", "$500/month at 10% grows to about $1,100,000", "$500/month at 10% grows to about $2,000,000"], correct: 2, explanation: "Investing $500/month at 10% annual returns for 30 years grows to approximately $1.1 million — from just $180,000 in contributions. The other ~$920,000 comes from compound growth. This is why starting early matters so much.", difficulty: "intermediate", topic: "general", learnLink: "index-funds" },
  { id: 150, question: "What is the most important factor in building long-term wealth?", options: ["Picking the right stocks", "Timing the market perfectly", "Starting early and investing consistently", "Having a high income"], correct: 2, explanation: "Starting early gives compound interest more time to work. Even small amounts invested consistently in low-cost index funds over decades outperform larger amounts invested later or sporadically. Time in the market is your greatest advantage.", difficulty: "beginner", topic: "general", learnLink: "index-funds" },
  { id: 151, question: "What is an annuity?", options: ["A type of stock", "An insurance product that provides guaranteed income payments, often in retirement", "A high-yield savings account", "A government bond"], correct: 1, explanation: "Annuities are insurance contracts that provide income payments in exchange for an upfront payment. While they offer guaranteed income, they often carry high fees and complex terms. Most financial experts recommend index funds over annuities for most people.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 152, question: "What is a SIMPLE IRA?", options: ["A simplified version of the S&P 500", "A retirement plan for small businesses with 100 or fewer employees", "A type of Roth IRA", "An individual trading account"], correct: 1, explanation: "A SIMPLE IRA (Savings Incentive Match Plan for Employees) is designed for small businesses. Employees can contribute up to $16,000 (2026) and employers must either match contributions up to 3% of compensation or make a flat 2% contribution.", difficulty: "intermediate", topic: "retirement", learnLink: "retirement" },
  { id: 153, question: "What is a growth at a reasonable price (GARP) strategy?", options: ["Only buying the cheapest stocks", "Finding growing companies that aren't overvalued — combining growth and value investing", "Investing only in large-cap stocks", "A fixed-income strategy"], correct: 1, explanation: "GARP combines growth and value investing by seeking companies with above-average growth that still trade at reasonable valuations (PEG ratio near 1). Legendary investor Peter Lynch was a prominent GARP practitioner.", difficulty: "advanced", topic: "stocks", learnLink: "stocks" },
  { id: 154, question: "What is an economic moat?", options: ["A body of water around a bank", "A sustainable competitive advantage that protects a company from competitors", "A government trade policy", "A type of bond"], correct: 1, explanation: "An economic moat (coined by Warren Buffett) is a durable competitive advantage — brand strength (Apple), network effects (Visa), switching costs (Microsoft), or cost advantages (Walmart). Companies with wide moats tend to sustain above-average profitability.", difficulty: "intermediate", topic: "stocks", learnLink: "stocks" },
  { id: 155, question: "What is a dividend yield?", options: ["The total return of a stock", "Annual dividend per share divided by the stock price, expressed as a percentage", "The growth rate of dividends", "The number of dividends paid per year"], correct: 1, explanation: "Dividend yield = annual dividend per share ÷ stock price. A stock at $100 paying $3/year in dividends has a 3% yield. High yields can indicate value (or a yield trap), while low yields often indicate growth companies reinvesting profits.", difficulty: "beginner", topic: "dividends", learnLink: "dividends" },
];
